import{b as e,J as l,g as n,j as a}from"./chunks/framework.DVAsBjJ_.js";const h=JSON.parse('{"title":"분양 조건 설정","description":"","frontmatter":{},"headers":[],"relativePath":"project/settings.md","filePath":"project/settings.md","lastUpdated":1780337107000}'),r={name:"project/settings.md"};function d(s,t,i,g,o,x){return l(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="분양-조건-설정" tabindex="-1">분양 조건 설정 <a class="header-anchor" href="#분양-조건-설정" aria-label="Permalink to &quot;분양 조건 설정&quot;">​</a></h1><p>프로젝트의 납부 일정, 계약금 및 공급 가격, 구비 서류, 유상 옵션 등 분양 계약에 직접적으로 적용되는 상세 조건을 설정합니다.</p><h2 id="납부-회차-등록" tabindex="-1">납부 회차 등록 <a class="header-anchor" href="#납부-회차-등록" aria-label="Permalink to &quot;납부 회차 등록&quot;">​</a></h2><p>계약금, 중도금, 잔금 등 분양 대금의 납부 회차를 정의하고, 각 회차별 납부 기한 및 선납할인/연체가산 기준을 설정합니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 설정 &gt; 분양 조건 설정 &gt; 납부 회차 등록</code></li></ul><h4 id="주요-입력-항목" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">타입 종류</td><td style="text-align:center;">필수</td><td style="text-align:left;">공동주택, 오피스텔 등 시설 용도별 회차 구분</td></tr><tr><td style="text-align:left;">회차 종류</td><td style="text-align:center;">필수</td><td style="text-align:left;">계약금, 중도금, 잔금, 업무대행비 등 항목 선택</td></tr><tr><td style="text-align:left;">계약금 산정방법</td><td style="text-align:center;"></td><td style="text-align:left;">(계약금인 경우) 등록 계약 금액 우선 또는 분양가 대비 비율 중 선택</td></tr><tr><td style="text-align:left;">납입회차 코드</td><td style="text-align:center;">필수</td><td style="text-align:left;"><strong>납부 시점(타이밍)</strong> 그룹화 코드. 동일 기한 내 납부 항목은 같은 코드 부여</td></tr><tr><td style="text-align:left;">납부순서</td><td style="text-align:center;">필수</td><td style="text-align:left;"><strong>수납 정산 우선순위</strong>. 입금 시 장부상 먼저 채워지는 절대적 순서</td></tr><tr><td style="text-align:left;">회차 명 / 별칭</td><td style="text-align:center;">필수</td><td style="text-align:left;">고지서 등에 표시될 회차 명칭</td></tr><tr><td style="text-align:left;">납부 약정금액</td><td style="text-align:center;"></td><td style="text-align:left;">정액으로 정해진 경우 입력 (예: 업무대행비)</td></tr><tr><td style="text-align:left;">납부비율(%)</td><td style="text-align:center;"></td><td style="text-align:left;">분양가 대비 납부 비율 (잔금은 자동 계산)</td></tr><tr><td style="text-align:left;">납부 약정일</td><td style="text-align:center;"></td><td style="text-align:left;">고정된 납부 기한이 있는 경우 입력</td></tr><tr><td style="text-align:left;">전회 기준 경과일수</td><td style="text-align:center;"></td><td style="text-align:left;">전 회차(예: 계약일)로부터 일정 기간 후 납부 시 설정</td></tr><tr><td style="text-align:left;">선납/연체 설정</td><td style="text-align:center;"></td><td style="text-align:left;">선납할인율, 연체가산율 및 각각의 적용 기준일 설정</td></tr></tbody></table><h4 id="💡-납입회차-코드-vs-납부순서-쉽게-이해하기" tabindex="-1">💡 납입회차 코드 vs 납부순서, 쉽게 이해하기 <a class="header-anchor" href="#💡-납입회차-코드-vs-납부순서-쉽게-이해하기" aria-label="Permalink to &quot;💡 납입회차 코드 vs 납부순서, 쉽게 이해하기&quot;">​</a></h4><p>두 항목을 구분하는 이유는 **&quot;동시에 내는 돈이라도 장부상 정산 순서가 다르기 때문&quot;**입니다.</p><ul><li><strong>납입회차 코드 (When)</strong>: &quot;언제 내는가?&quot; 즉, 고지서에 묶여서 나가는 <strong>납부 그룹</strong>입니다.</li><li><strong>납부순서 (Priority)</strong>: &quot;무엇을 먼저 채우는가?&quot; 즉, 입금 시 <strong>장부 정산 순위</strong>입니다.</li></ul><p><strong>[사례: 2회차 기한에 계약금과 업무대행비를 각각 1,000만 원씩 받는 경우]</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">항목 명칭</th><th style="text-align:center;"><strong>회차 코드 (시점)</strong></th><th style="text-align:center;"><strong>납부 순서 (우선순위)</strong></th><th style="text-align:left;">시스템 정산 로직</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>2차 계약금</strong></td><td style="text-align:center;"><strong>2</strong></td><td style="text-align:center;"><strong>2</strong></td><td style="text-align:left;">입금액 발생 시 가장 먼저 채워짐</td></tr><tr><td style="text-align:left;"><strong>업무대행비</strong></td><td style="text-align:center;"><strong>2</strong></td><td style="text-align:center;"><strong>3</strong></td><td style="text-align:left;">계약금이 다 채워진 후 남은 금액이 채워짐</td></tr></tbody></table><ul><li><strong>설정 이유</strong>: 만약 계약자가 2,000만 원 중 <strong>1,500만 원만 입금</strong>했다면, 시스템은 <strong>납부순서</strong>에 따라 [2차 계약금] 1,000만 원을 완납 처리하고, 남은 500만 원을 [업무대행비]의 일부로 배정합니다.</li></ul><h2 id="계약-금액-등록" tabindex="-1">계약 금액 등록 <a class="header-anchor" href="#계약-금액-등록" aria-label="Permalink to &quot;계약 금액 등록&quot;">​</a></h2><p>차수 및 타입별로 고정된 계약 금액을 설정합니다.</p><ul><li><p><strong>등록 대상</strong>: 동호 미지정 계약이나 타입별(층별 구분 없이) 일괄 정액제 계약금을 운영할 때 등록합니다.</p></li><li><p><strong>적용 우선순위</strong>: 계약금 회차의 금액은 다음 순서로 결정됩니다.</p><ol><li><strong>회차별 고정 금액</strong>: [납부 회차 등록]에서 직접 입력한 &#39;납부 약정금액&#39;</li><li><strong>특별 약정 금액</strong>: [공급 가격 등록]의 &#39;특별약정 추가&#39;로 등록된 금액</li><li><strong>타입별 계약 금액</strong>: 본 메뉴([계약 금액 등록])에서 설정한 정액 금액 (납부비율보다 우선 적용)</li><li><strong>납부 비율 계산</strong>: [납부 회차 등록]의 &#39;납부비율(%)&#39;을 공급가에 곱한 금액</li></ol></li><li><p><strong>참고</strong>: 각 유닛별 공급 가격의 일정 비율을 계약금으로 정하는 일반적인 경우에는 [납부 회차 등록]의 납입 비율이 자동 적용되므로 별도로 이 데이터를 등록할 필요가 없습니다.</p></li><li><p><strong>위치</strong>: <code>프로젝트 설정 &gt; 분양 조건 설정 &gt; 계약 금액 등록</code></p></li></ul><h4 id="주요-입력-항목-1" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목-1" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">차수</td><td style="text-align:center;">필수</td><td style="text-align:left;">대상 계약 차수 그룹 선택</td></tr><tr><td style="text-align:left;">타입</td><td style="text-align:center;">필수</td><td style="text-align:left;">대상 유닛 타입 선택</td></tr><tr><td style="text-align:left;">회차별 납부금액</td><td style="text-align:center;">필수</td><td style="text-align:left;">해당 차수/타입에 적용할 정액 계약금액</td></tr></tbody></table><h2 id="공급-가격-등록" tabindex="-1">공급 가격 등록 <a class="header-anchor" href="#공급-가격-등록" aria-label="Permalink to &quot;공급 가격 등록&quot;">​</a></h2><p>동/타입/층별 범위에 따른 실제 공급 가격을 등록합니다. 건물가, 대지가, 부가세를 구분하여 관리합니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 설정 &gt; 분양 조건 설정 &gt; 공급 가격 등록</code></li><li><strong>산출 우선순위</strong>: 시스템은 다음 순서에 따라 계약 가격을 결정합니다. <ol><li><strong>개별 계약 가격</strong>: 특정 계약건에 별도로 입력된 가격 (최우선)</li><li><strong>기준 공급 가격</strong>: 본 메뉴([공급 가격 등록])에서 설정한 차수/타입/층별 가격</li><li><strong>프로젝트 예산 단가</strong>: [수입 예산 등록]에서 설정한 항목별 평균 단가</li><li><strong>타입별 평균 단가</strong>: [타입 정보 등록]에서 설정한 평균 가격</li></ol></li></ul><h4 id="주요-입력-항목-2" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목-2" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">구분 / 차수 / 타입</td><td style="text-align:center;">필수</td><td style="text-align:left;">가격을 등록할 상세 범위 선택</td></tr><tr><td style="text-align:left;">층별 조건</td><td style="text-align:center;">필수</td><td style="text-align:left;">등록된 층 범위(저층, 기준층 등) 선택</td></tr><tr><td style="text-align:left;">건물가 / 대지가</td><td style="text-align:center;">필수</td><td style="text-align:left;">각 항목별 금액 입력 (단위: 원)</td></tr><tr><td style="text-align:left;">부가세</td><td style="text-align:center;">필수</td><td style="text-align:left;">건물분에 대한 부가세 입력</td></tr><tr><td style="text-align:left;">기준공급가</td><td style="text-align:center;">필수</td><td style="text-align:left;">건물가 + 대지가 + 부가세 합계 (자동 계산)</td></tr><tr><td style="text-align:left;">특별약정 추가</td><td style="text-align:center;"></td><td style="text-align:left;">특정 회차에 대해 비율이 아닌 확정 금액을 적용할 경우 설정</td></tr></tbody></table><h4 id="전체-계약건-공급가-재설정-관리자-전용" tabindex="-1">전체 계약건 공급가 재설정 (관리자 전용) <a class="header-anchor" href="#전체-계약건-공급가-재설정-관리자-전용" aria-label="Permalink to &quot;전체 계약건 공급가 재설정 (관리자 전용)&quot;">​</a></h4><p>공급 가격이나 계약 금액 정보를 수정한 후, 이미 등록된 모든 계약 데이터에 변경된 내용을 일괄 반영할 때 사용합니다.</p><ul><li><strong>미리보기</strong>: 실제 반영 전 업데이트 대상 계약 건수와 샘플 데이터를 콘솔 등을 통해 확인합니다.</li><li><strong>전체 공급가 재설정</strong>: 현재 등록된 최신 공급 가격 및 계약 금액 데이터를 기반으로 모든 계약 건의 가격 정보를 강제로 재설정합니다.</li><li><strong>주의사항</strong>: 이 작업은 복구가 불가능하며 등록된 모든 계약 데이터의 수납 약정 금액이 변경될 수 있으므로 매우 신중하게 실행해야 합니다.</li></ul><h2 id="구비-서류-등록" tabindex="-1">구비 서류 등록 <a class="header-anchor" href="#구비-서류-등록" aria-label="Permalink to &quot;구비 서류 등록&quot;">​</a></h2><p>계약 시 계약자가 제출해야 하는 증빙 서류 및 동의서 목록을 관리합니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 설정 &gt; 분양 조건 설정 &gt; 구비 서류 등록</code></li></ul><h4 id="주요-입력-항목-3" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목-3" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">서류구분</td><td style="text-align:center;">필수</td><td style="text-align:left;">증빙서류 또는 동의서류(약정서 등) 중 선택</td></tr><tr><td style="text-align:left;">서류 유형</td><td style="text-align:center;">필수</td><td style="text-align:left;">주민등록등본, 인감증명서 등 세부 유형 선택</td></tr><tr><td style="text-align:left;">필요 수량</td><td style="text-align:center;"></td><td style="text-align:left;">제출 받아야 할 서류 부수</td></tr><tr><td style="text-align:left;">필수 여부</td><td style="text-align:center;">필수</td><td style="text-align:left;">필수, 선택, 조건부 필수 중 선택</td></tr><tr><td style="text-align:left;">설명 / 표시 순서</td><td style="text-align:center;"></td><td style="text-align:left;">서류 지참 안내 시 참고사항 및 목록 노출 순서</td></tr></tbody></table><h2 id="옵션-품목-등록" tabindex="-1">옵션 품목 등록 <a class="header-anchor" href="#옵션-품목-등록" aria-label="Permalink to &quot;옵션 품목 등록&quot;">​</a></h2><p>발코니 확장, 시스템 에어컨, 가전제품 등 수분양자가 선택할 수 있는 유상 옵션 품목을 관리합니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 설정 &gt; 분양 조건 설정 &gt; 옵션 품목 등록</code></li></ul><h4 id="주요-입력-항목-4" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목-4" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">타입구분</td><td style="text-align:center;">필수</td><td style="text-align:left;">해당 옵션을 선택할 수 있는 대상 타입 (다중 선택 가능)</td></tr><tr><td style="text-align:left;">품목 코드 / 이름</td><td style="text-align:center;">필수</td><td style="text-align:left;">옵션 품목 식별 정보</td></tr><tr><td style="text-align:left;">세대 옵션</td><td style="text-align:center;"></td><td style="text-align:left;">규격, 색상 등 세부 선택 사항</td></tr><tr><td style="text-align:left;">제조사</td><td style="text-align:center;"></td><td style="text-align:left;">품목의 제조사 또는 브랜드</td></tr><tr><td style="text-align:left;">옵션 가격</td><td style="text-align:center;">필수</td><td style="text-align:left;">총 판매 가격</td></tr><tr><td style="text-align:left;">계약금 / 잔금</td><td style="text-align:center;"></td><td style="text-align:left;">옵션 대금의 분납 시 각 금액 설정</td></tr></tbody></table><h2 id="💡-산출-로직-요약-안내" tabindex="-1">💡 산출 로직 요약 안내 <a class="header-anchor" href="#💡-산출-로직-요약-안내" aria-label="Permalink to &quot;💡 산출 로직 요약 안내&quot;">​</a></h2><p>IBS 시스템은 유연한 분양가 운영을 위해 다단계 우선순위 로직을 사용합니다.</p><h3 id="_1-공급-가격-contract-price" tabindex="-1">1. 공급 가격 (Contract Price) <a class="header-anchor" href="#_1-공급-가격-contract-price" aria-label="Permalink to &quot;1. 공급 가격 (Contract Price)&quot;">​</a></h3><p>시스템은 계약서 생성 시 <strong>[개별 계약 가격 &gt; 기준 공급 가격 &gt; 예산 단가 &gt; 타입 단가]</strong> 순으로 유효한 값을 찾아 적용합니다. 따라서 상세한 공급 가격을 등록하기 전이라도 예산이나 타입 정보만 있다면 대략적인 분양가 산출이 가능합니다.</p><h3 id="_2-회차별-납부-금액-payment-amount" tabindex="-1">2. 회차별 납부 금액 (Payment Amount) <a class="header-anchor" href="#_2-회차별-납부-금액-payment-amount" aria-label="Permalink to &quot;2. 회차별 납부 금액 (Payment Amount)&quot;">​</a></h3><p>각 납부 회차의 금액은 설정된 <strong>적용 범위</strong>에 따라 다음 우선순위로 결정됩니다.</p><table tabindex="0"><thead><tr><th style="text-align:center;">순위</th><th style="text-align:left;">항목 명칭</th><th style="text-align:left;">설정 메뉴</th><th style="text-align:left;"><strong>적용 범위 (Scope)</strong></th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>1</strong></td><td style="text-align:left;"><strong>회차별 고정 금액</strong></td><td style="text-align:left;">[납부 회차 등록]</td><td style="text-align:left;"><strong>프로젝트 전체</strong></td><td style="text-align:left;">모든 타입/동/층에 동일 정액 적용 (예: 업무대행비)</td></tr><tr><td style="text-align:center;"><strong>2</strong></td><td style="text-align:left;"><strong>특별 약정 금액</strong></td><td style="text-align:left;">[공급 가격 등록]</td><td style="text-align:left;"><strong>특정 가격 조건</strong></td><td style="text-align:left;">특정 차수+타입+층별 조건에만 예외적 정액 적용</td></tr><tr><td style="text-align:center;"><strong>3</strong></td><td style="text-align:left;"><strong>타입별 계약 금액</strong></td><td style="text-align:left;">[계약 금액 등록]</td><td style="text-align:left;"><strong>특정 타입별</strong></td><td style="text-align:left;">특정 타입 전체에 동일한 정액 계약금 적용</td></tr><tr><td style="text-align:center;"><strong>4</strong></td><td style="text-align:left;"><strong>납부 비율 계산</strong></td><td style="text-align:left;">[납부 회차 등록]</td><td style="text-align:left;"><strong>프로젝트 전체</strong></td><td style="text-align:left;">(기본값) 공급 가격에 설정된 비율(%)을 곱하여 산출</td></tr></tbody></table><h4 id="💡-왜-이렇게-복잡하게-구분하나요" tabindex="-1">💡 왜 이렇게 복잡하게 구분하나요? <a class="header-anchor" href="#💡-왜-이렇게-복잡하게-구분하나요" aria-label="Permalink to &quot;💡 왜 이렇게 복잡하게 구분하나요?&quot;">​</a></h4><p>다양한 분양 전략을 유연하게 지원하기 위해서입니다.</p><ul><li><strong>예시 1</strong>: 모든 세대의 &#39;업무대행비&#39;는 동일하게 1,000만 원으로 고정하고 싶은 경우 -&gt; <strong>회차별 고정 금액(1순위)</strong> 사용</li><li><strong>예시 2</strong>: 대부분 10% 비율제지만, &#39;펜트하우스&#39;만 계약금을 5,000만 원 정액으로 받고 싶은 경우 -&gt; <strong>특별 약정 금액(2순위)</strong> 사용</li><li><strong>예시 3</strong>: 동호 지정 전이라 층별 가격이 확정되지 않았지만, &#39;84타입&#39;은 무조건 3,000만 원을 계약금으로 받는 경우 -&gt; <strong>타입별 계약 금액(3순위)</strong> 사용</li><li><strong>일반적인 경우</strong>: [납부 회차 등록]에서 **납부 비율(4순위)**만 설정하면 모든 유닛의 가격에 맞춰 자동으로 금액이 산출됩니다.</li><li><strong>잔금 산출</strong>: 잔금은 [총 공급가 - (계약금 + 중도금 + 기타 회차 합계)]로 자동 계산되어 단수 차액을 조정합니다.</li></ul>',46)])])}const f=e(r,[["render",d]]);export{h as __pageData,f as default};
